-- ملء محتوى عنقود "الولاية في الإسلام" (wilaya-islamiyya) — تصنيفان فرعيان،
-- كلاهما draft (استنفاد كامل للعنقود): الولاية الخاصة وولاية الأب والمال
-- والوصاية، الولاية العامة والإمامة والقضاء والحسبة.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس usul-fiqh/qawaid-fiqhiyya
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الفقه الإسلامي وأدلته لوهبة الزحيلي (ولاية خاصة)،
-- الأحكام السلطانية لأبي الحسن الماوردي (ولاية عامة).
-- حديثان استُشهد بهما، تحقَّقا حرفياً عبر WebSearch قبل الإدراج (كلاهما
-- صحيح): "كلكم راع وكلكم مسؤول عن رعيته..." (متفق عليه، البخاري 7138
-- ومسلم 1829)، و"من رأى منكم منكرًا فليغيره بيده..." (رواه مسلم).
-- آيتان تحقَّقتا حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: النساء 6، النساء 58.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفين عند اكتمالهما.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الولاية الخاصة وولاية الأب والمال والوصاية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7ed54f39-316f-4b77-9340-f90fd8ae301c' AND title='الولاية الخاصة: ولاية الأب على النفس والمال والوصاية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الولاية الخاصة: ولاية الأب على النفس والمال والوصاية', 'تعريف موجز بالولاية الخاصة وأقسامها وترتيب أصحابها والوصاية كامتداد لها', '7ed54f39-316f-4b77-9340-f90fd8ae301c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف الولاية الخاصة وأقسامها', 'الولاية الخاصة سلطة شرعية يملك بها الولي إنشاء تصرف نافذ على غيره ممن لا يملك التصرف بنفسه، كالصغير والمجنون، رعايةً لمصلحته. وتنقسم إلى نوعين: ولاية على النفس، وتشمل التربية والتأديب والتزويج؛ وولاية على المال، وتشمل حفظ مال القاصر واستثماره والتصرف فيه بما يحقق مصلحته. وأصحاب هذه الولاية مرتبون: الأب أولاً، فإن عُدم فالجد لأب، فإن عُدم فمن نصّبه الأب أو الجد وصيًّا، فإن لم يوجد أحد منهم فالقاضي أو من ينيبه. ويُشترط في الولي: البلوغ والعقل والأمانة والقدرة على القيام بمصلحة المولى عليه؛ فمن فقد الأمانة أو ظهر منه تفريط عزله القاضي ونصب غيره. والوصاية امتداد لولاية الأب بعد موته، إذ يجوز له أن يعهد بها إلى أمين يقوم مقامه في رعاية أولاده القُصَّر وأموالهم.', 1),
    (v_lesson, 'examples', 'أصلا الولاية الخاصة من القرآن والسنة', 'قال تعالى: ﴿وَابْتَلُوا الْيَتَامَىٰ حَتَّىٰ إِذَا بَلَغُوا النِّكَاحَ فَإِنْ آنَسْتُم مِّنْهُمْ رُشْدًا فَادْفَعُوا إِلَيْهِمْ أَمْوَالَهُمْ ۖ وَلَا تَأْكُلُوهَا إِسْرَافًا وَبِدَارًا أَن يَكْبَرُوا ۚ وَمَن كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ ۖ وَمَن كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ ۚ فَإِذَا دَفَعْتُمْ إِلَيْهِمْ أَمْوَالَهُمْ فَأَشْهِدُوا عَلَيْهِمْ ۚ وَكَفَىٰ بِاللَّهِ حَسِيبًا﴾ (النساء: 6)، وهي الأصل في ضبط ولاية المال على اليتامى: اختبار رشدهم قبل التسليم، وتحريم أكل أموالهم، ووجوب الإشهاد عند الدفع إليهم. وقال النبي صلى الله عليه وسلم: "ألا كلكم راعٍ وكلكم مسؤول عن رعيته، فالأمير الذي على الناس راعٍ وهو مسؤول عن رعيته، والرجل راعٍ على أهل بيته وهو مسؤول عنهم" (متفق عليه)، وهو الأصل الذي بُنيت عليه مسؤولية الولي عمن تحت ولايته، صغيرًا كان أم مالاً.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — وهبة الزحيلي', 1);
  END IF;

  -- 2) الولاية العامة والإمامة والقضاء والحسبة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e68be399-d394-4ced-9fe5-1cb463190102' AND title='الولاية العامة: الإمامة والقضاء والحسبة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الولاية العامة: الإمامة والقضاء والحسبة', 'تعريف موجز بالولاية العامة وأقسامها الثلاثة وشروط كل منها', 'e68be399-d394-4ced-9fe5-1cb463190102', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أقسام الولاية العامة وشروطها', 'الولاية العامة سلطة شرعية تتعلق بمصالح الأمة عامة لا بشخص بعينه، وتنقسم عند الفقهاء إلى ثلاثة أبواب كبرى: الإمامة الكبرى، وهي رئاسة عامة في أمور الدين والدنيا خلافةً عن النبوة، ويُشترط في الإمام العلم والعدالة والكفاية والسلامة من الآفات المانعة من القيام بأعباء المنصب؛ والقضاء، وهو ولاية الفصل بين الناس بالحق فصلاً ملزمًا، ويُشترط في القاضي العلم بأحكام الشرع والعدالة والقدرة على الاستنباط؛ والحسبة، وهي ولاية الأمر بالمعروف إذا ظهر تركه والنهي عن المنكر إذا ظهر فعله، ويقوم بها المحتسب في مراقبة الأسواق والآداب العامة وما ظهر من المخالفات دون الحاجة إلى دعوى أو حكم قضائي. وتشترك هذه الأبواب الثلاثة في كونها أمانة يُحاسَب صاحبها على القيام بحقها لا مجرد سلطة يُتصرف بها لمصلحة شخصية.', 1),
    (v_lesson, 'examples', 'أصلا الولاية العامة من القرآن والسنة', 'قال تعالى: ﴿إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ النَّاسِ أَن تَحْكُمُوا بِالْعَدْلِ ۚ إِنَّ اللَّهَ نِعِمَّا يَعِظُكُم بِهِ ۗ إِنَّ اللَّهَ كَانَ سَمِيعًا بَصِيرًا﴾ (النساء: 58)، وهي الأصل الجامع لواجبَي الإمامة والقضاء معًا: أداء الأمانة إلى أهلها، والحكم بين الناس بالعدل. وقال النبي صلى الله عليه وسلم: "من رأى منكم منكرًا فليغيره بيده، فإن لم يستطع فبلسانه، فإن لم يستطع فبقلبه، وذلك أضعف الإيمان" (رواه مسلم)، وهو الأصل الذي بُنيت عليه ولاية الحسبة في تغيير المنكر بحسب القدرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأحكام السلطانية — أبو الحسن الماوردي', 1);
  END IF;

  -- تحديث حالة التصنيفين إلى منشور بعد اكتمال محتواهما
  UPDATE categories SET status='published'
  WHERE id IN (
    '7ed54f39-316f-4b77-9340-f90fd8ae301c', 'e68be399-d394-4ced-9fe5-1cb463190102'
  );
END $$;
